parameter integer N = 4;
function integer log2;
  input integer x;
  integer i;
  begin
    i = 0;
    while ((1 << i) < x) i = i + 1;
    log2 = i;
  end
endfunction
genvar j;
generate
  for (j = 0; j < log2(N + 1); j = j + 1)
    assign w[j] = 1'b0;
endgenerate

